module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);

    reg [32:0] res;
    assign r = res[31:0];
    assign zero = (res[31:0] == 0);
    assign negative = res[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? res[31] : 1'bz;
    always @(*) begin
        case (aluc)
            ADD: res = {a[31], a} + {b[31], b};
            ADDU: res = {32'b0, a} + {32'b0, b};
            SUB: res = {a[31], a} - {b[31], b};
            SUBU: res = {32'b0, a} - {32'b0, b};
            AND: res = {33'b0, a & b};
            OR: res = {33'b0, a | b};
            XOR: res = {33'b0, a ^ b};
            NOR: res = {33'b0, ~(a | b)};
            SLT: res = {33'b0, (a < b)};
            SLTU: res = {33'b0, (a < b)};
            SLL: res = {b[31:0], 1'b0};
            SRL: res = {1'b0, b[31:1]};
            SRA: res = {{1{b[31]}}, b[31:1]};
            SLLV: res = {b[31:0], 1'b0};
            SRLV: res = {1'b0, b[31:1]};
            SRAV: res = {{1{b[31]}}, b[31:1]};
            LUI: res = {a[15:0], 16'b0};
            default: res = 33'bz;
        endcase
        carry = (aluc == ADD || aluc == ADDU) ? res[32] : (aluc == SUB || aluc == SUBU) ? res[32] : 1'b0;
        overflow = (aluc == ADD || aluc == ADDU) ? ((~a[31] & ~b[31] & res[31]) | (a[31] & b[31] & ~res[31])) : (aluc == SUB || aluc == SUBU) ? ((a[31] & ~b[31] & ~res[31]) | (~a[31] & b[31] & res[31])) : 1'b0;
    end
endmodule
